def missing_inds(x, format_data=True):

    if format_data:
        x = formatter(x, ppca=False)

    inds = []
    for arr in x:
        if np.argwhere(np.isnan(arr)).size == 0:
            inds.append(None)
        else:
            inds.append(np.argwhere(np.isnan(arr))[:,0])
    if len(inds) > 1:
        return inds
    else:
        return inds[0]

