def fill_missing(x):

    m = PPCA()
    m.fit(data=np.vstack(x))
    x_pca = m.transform()

    all_missing = [idx for idx, a in enumerate(np.vstack(x)) if all([type(b)==np.nan for b in a])]
    if len(all_missing)>0:
        for i in all_missing:
